package com.example.worktimetracker;
import java.text.SimpleDateFormat;import java.util.Calendar;import java.util.Date;import java.util.Locale;
final class TimeUtils{static final long POLL_MS=1000L,UI_REFRESH_MS=1000L,DEFAULT_IDLE_LIMIT_MS=10L*60L*1000L;private TimeUtils(){}static String toIso(long m){return new SimpleDateFormat("yyyy-MM-dd HH:mm:ss",Locale.US).format(new Date(m));}static String gregDate(long m){return new SimpleDateFormat("yyyy-MM-dd",Locale.US).format(new Date(m));}static String hhmmss(long m){return new SimpleDateFormat("HH:mm:ss",Locale.US).format(new Date(m));}static String hhmm(long m){return new SimpleDateFormat("HH:mm",Locale.US).format(new Date(m));}static String fmtHms(long s){if(s<0)s=0;long h=s/3600,mi=(s%3600)/60,se=s%60;return h+":"+String.format(Locale.US,"%02d:%02d",mi,se);}static long dayStart(long m){Calendar c=Calendar.getInstance();c.setTimeInMillis(m);c.set(Calendar.HOUR_OF_DAY,0);c.set(Calendar.MINUTE,0);c.set(Calendar.SECOND,0);c.set(Calendar.MILLISECOND,0);return c.getTimeInMillis();}static long nextDayStart(long m){Calendar c=Calendar.getInstance();c.setTimeInMillis(dayStart(m));c.add(Calendar.DAY_OF_MONTH,1);return c.getTimeInMillis();}static long addDays(long m,int d){Calendar c=Calendar.getInstance();c.setTimeInMillis(m);c.add(Calendar.DAY_OF_MONTH,d);return c.getTimeInMillis();}}
